"""Only ds2 contains null values. Hence, we can do an outer join and standardise naming conventions for countries later, without worrying about excessive null values.

#Data Structuring

As mentioned earlier, we need to drop Sierra Leone due to its inaccurate data. To facilitate merging later, we standardise the country column name.
"""

df_ds2_selected = df_ds2_selected[df_ds2_selected['country'] != 'Sierra Leone']
df_ds3 = df_ds3[df_ds3_selected['Entity'] != 'Sierra Leone']
df_ds3 = df_ds3.rename(columns={'Entity': 'country'})
df_ds5_selected_cleaned = df_ds5_selected[df_ds5_selected['Label'] != 'Sierra Leone']
df_ds5_selected_cleaned = df_ds5_selected_cleaned.rename(columns={'Label': 'country'})



print(df_ds2_selected)
print(df_ds3)
print(df_ds5_selected_cleaned)

"""Because there are multiple repeated countries with different years, we decide to do a pivot table for ds3, facilitating the imputation of null entries later on as well as the merging of datasets."""

df_ds3_cleaned_pivot = df_ds3.pivot_table(index=['country'], columns='Year', values='Total alcohol consumption per capita (liters of pure alcohol, projected estimates, 15+ years of age)', aggfunc='mean')
df_ds3_cleaned_pivot = df_ds3_cleaned_pivot.reset_index()
print(df_ds3_cleaned_pivot)
#

"""##Data Enrichment

Now, we can merge all three datasets: ds2, ds3 and ds5. We perform an outer join to minimise loss of data.
"""

joined_df=pd.merge(df_ds2_selected, df_ds3_cleaned_pivot, on='country', how='outer')
joined_ds=pd.merge(joined_df, df_ds5_selected_cleaned, on='country', how='outer')
print(joined_ds)
print(f"Total null values: {joined_ds.isnull().sum()}")
