"""Strangely, total unique countries seem to have increased. Upon closer inspection, it seems that certain countries have different names across the datasets, for examples "Viet Nam" vs "Vietnam". Hence, we will have to clean the data first.

# Data cleaning
"""

import pycountry
import pandas as pd

# Standard replacements
COUNTRY_REPLACEMENTS = {
    'Antigua & Barbuda': 'Antigua and Barbuda',
    'Bosnia Herzegovina': 'Bosnia and Herzegovina',
    'Bosnia-Herzegovina': 'Bosnia and Herzegovina',
    'Cape Verde': 'Cabo Verde',
    'Congo, Republic of': 'Congo',
    'DR Congo': 'Congo, The Democratic Republic of the',
    'Congo, Democratic Republic of the': 'Congo, The Democratic Republic of the',
    'Congo, Democratic Republic of': 'Congo, The Democratic Republic of the',
    'Cote d\'Ivoire': 'Côte d\'Ivoire',
    'France (metropolitan)': 'France',
    'France, Guadeloupe': 'France',
    'France, La Réunion': 'France',
    'France, Martinique': 'France',
    'French Guyana': 'France Guiana',
    'French Southern Territories': 'France',
    'USA': 'United States',
    'UK': 'United Kingdom',
    'Republic of Korea': 'Korea, Republic of',
    'South Korea': 'Korea, Republic of',
    'North Korea': 'Korea, Democratic People\'s Republic of',
    'Korea (Democratic People Republic of)': 'Korea, Democratic People\'s Republic of',
    'Czechia': 'Czech Republic',
    'Vietnam': 'Viet Nam',
    'Iran': 'Iran, Islamic Republic of',
    'Iran, (Islamic Republic of)': 'Iran, Islamic Republic of',
    'Sao Tome & Principe': 'Sao Tome and Principe',
    'Syria': 'Syrian Arab Republic',
    'Trinidad & Tobago': 'Trinidad and Tobago',
    'Turkey': 'Türkiye',
    'Taiwan': 'Taiwan, Province of China',
    'Bolivia': 'Bolivia, Plurinational State of',
    'Tanzania': 'Tanzania, United Republic of',
    'Venezuela': 'Venezuela, Bolivarian Republic of',
    'Laos': 'Lao People\'s Democratic Republic',
    'Brunei': 'Brunei Darussalam',
    'Moldova': 'Moldova, Republic of',
    'Russia':'Russian Federation'
    }

def standardize_country_name(name):
    if pd.isna(name):
        return None
    name = str(name).strip()
    name = COUNTRY_REPLACEMENTS.get(name, name)
    try:
        return pycountry.countries.lookup(name).name
    except LookupError:
        return name

def standardize_country_column(df, column_name):
    df['country'] = df['country'].apply(standardize_country_name)
    return df

def convert_iso_numeric_to_name(code):
    if pd.isna(code):
        return None
    try:
        code_int = int(code)
        for country in pycountry.countries:
            if hasattr(country, 'numeric') and int(country.numeric) == code_int:
                return country.name
    except (ValueError, TypeError):
        return None
    return None

# Apply transformations
df_ds2_selected = standardize_country_column(df_ds2_selected, 'country')
df_ds3_cleaned_pivot = standardize_country_column(df_ds3_cleaned_pivot, 'country')
df_ds5_selected_cleaned = standardize_country_column(df_ds5_selected_cleaned, 'country')

"""# Data enriching by integrating DS2, DS3 and DS5"""

# Inner join
joined_ds = pd.merge(df_ds2_selected, df_ds3_cleaned_pivot, on='country', how='inner')
joined_ds = pd.merge(joined_ds, df_ds5_selected_cleaned, on='country', how='inner')

# Summary
print(joined_ds.head())
