"""# Data enriching by adding new attributes (beer, wine and spirit consumption level)

We categorise countries' consumption level of beer, wine and spirit into low, medium, high and ultra high and analysed the differenes in consumption between countries.
"""

import pandas as pd

# Assuming joined_ds is already defined and contains beer_servings, wine_servings, and spirit_servings

# Calculate percentiles for each column
beer_low = joined_ds['beer_servings'].quantile(0.3)
beer_high = joined_ds['beer_servings'].quantile(0.6)
ultra_high = joined_ds['beer_servings'].quantile(0.9)

wine_low = joined_ds['wine_servings'].quantile(0.3)
wine_high = joined_ds['wine_servings'].quantile(0.6)
ultra_high = joined_ds['wine_servings'].quantile(0.9)

spirit_low = joined_ds['spirit_servings'].quantile(0.3)
spirit_high = joined_ds['spirit_servings'].quantile(0.6)
ultra_high = joined_ds['spirit_servings'].quantile(0.9)

def apply_servings_level_dynamic(servings, low, high):
    if servings < low:
        return 'Low'
    elif low <= servings < high:
        return 'Medium'
    elif high<= servings <ultra_high:
        return 'High'
    elif servings>= ultra_high:
        return 'Ultra High'
    else:
        return 'Unknown'

joined_ds['beer_consumption_level'] = joined_ds['beer_servings'].apply(apply_servings_level_dynamic, args=(beer_low, beer_high))
joined_ds['wine_consumption_level'] = joined_ds['wine_servings'].apply(apply_servings_level_dynamic, args=(wine_low, wine_high))
joined_ds['spirit_consumption_level'] = joined_ds['spirit_servings'].apply(apply_servings_level_dynamic, args=(spirit_low, spirit_high))

total = len(joined_ds)

print(f"Percentage of beer_consumption_level: "
      f"Low: {((joined_ds['beer_consumption_level'] == 'Low').sum() / total) * 100:.2f}%, "
      f"Medium: {((joined_ds['beer_consumption_level'] == 'Medium').sum() / total) * 100:.2f}%, "
      f"High: {((joined_ds['spirit_consumption_level'] == 'High').sum() / total) * 100:.2f}%, "
      f"Ultra_High: {((joined_ds['spirit_consumption_level'] == 'Ultra_High').sum() / total) * 100:.2f}%")

print(f"Percentage of wine_consumption_level: "
      f"Low: {((joined_ds['wine_consumption_level'] == 'Low').sum() / total) * 100:.2f}%, "
      f"Medium: {((joined_ds['wine_consumption_level'] == 'Medium').sum() / total) * 100:.2f}%, "
      f"High: {((joined_ds['spirit_consumption_level'] == 'High').sum() / total) * 100:.2f}%, "
      f"Ultra_High: {((joined_ds['spirit_consumption_level'] == 'Ultra_High').sum() / total) * 100:.2f}%")

