"""**Histogram for beer, wine, and spirit consumption level**"""

import matplotlib.pyplot as plt
import seaborn as sns

def plot_servings_distribution_same_range(df, beer_low, beer_high, ultra_high, wine_low, wine_high, spirit_low, spirit_high):
    min_value = min(df['beer_servings'].min(), df['wine_servings'].min(), df['spirit_servings'].min())
    max_value = max(df['beer_servings'].max(), df['wine_servings'].max(), df['spirit_servings'].max())

    fig, axes = plt.subplots(3, 1, figsize=(10, 18))

    sns.histplot(df['beer_servings'], bins=20, kde=True, color='skyblue', ax=axes[0], stat='density', common_norm=False)
    axes[0].axvline(x=beer_low, color='red', linestyle='--', label=f'Beer Low Boundary ({beer_low})')
    axes[0].axvline(x=beer_high, color='orange', linestyle='--', label=f'Beer High Boundary ({beer_high})')
    axes[0].axvline(x=ultra_high, color='green', linestyle='--', label=f'Beer Ultra High Boundary ({ultra_high})')
    axes[0].set_title('Beer Servings Distribution with Consumption Levels')
    axes[0].set_xlabel('Beer Servings')
    axes[0].set_ylabel('Density')
    axes[0].legend()
    axes[0].set_xlim(min_value, max_value)

    sns.histplot(df['wine_servings'], bins=20, kde=True, color='orange', ax=axes[1], stat='density', common_norm=False)
    axes[1].axvline(x=wine_low, color='purple', linestyle='--', label=f'Wine Low Boundary ({wine_low})')
    axes[1].axvline(x=wine_high, color='brown', linestyle='--', label=f'Wine High Boundary ({wine_high})')
    axes[1].axvline(x=ultra_high, color='green', linestyle='--', label=f'Wine Ultra High Boundary ({ultra_high})')
    axes[1].set_title('Wine Servings Distribution with Consumption Levels')
    axes[1].set_xlabel('Wine Servings')
    axes[1].set_ylabel('Density')
    axes[1].legend()
    axes[1].set_xlim(min_value, max_value)

    sns.histplot(df['spirit_servings'], bins=20, kde=True, color='green', ax=axes[2], stat='density', common_norm=False)
    axes[2].axvline(x=spirit_low, color='blue', linestyle='--', label=f'Spirit Low Boundary ({spirit_low})')
    axes[2].axvline(x=spirit_high, color='pink', linestyle='--', label=f'Spirit High Boundary ({spirit_high})')
    axes[2].axvline(x=ultra_high, color='green', linestyle='--', label=f'Spirit Ultra High Boundary ({ultra_high})')
    axes[2].set_title('Spirit Servings Distribution with Consumption Levels')
    axes[2].set_xlabel('Spirit Servings')
    axes[2].set_ylabel('Density')
    axes[2].legend()
    axes[2].set_xlim(min_value, max_value)

    plt.tight_layout()
    plt.show()

plot_servings_distribution_same_range(joined_ds, beer_low, beer_high, ultra_high, wine_low, wine_high, spirit_low, spirit_high)

